import{_ as l,c as i,o as a,a4 as e}from"./chunks/framework.l5PdLkab.js";const r=JSON.parse('{"title":"[3D프린터] 20181219수","description":"","frontmatter":{},"headers":[],"relativePath":"tools-software/3dprinter-meshmixer.md","filePath":"tools-software/3dprinter-meshmixer.md","lastUpdated":1781570900000}');const t=l({name:"tools-software/3dprinter-meshmixer.md"},[["render",function(l,r,t,o,h,p){return a(),i("div",null,r[0]||(r[0]=[e('<h1 id="_3d프린터-20181219수" tabindex="-1">[3D프린터] 20181219수 <a class="header-anchor" href="#_3d프린터-20181219수" aria-label="Permalink to &quot;[3D프린터] 20181219수&quot;">​</a></h1><p>실제 사업을 하기 위해서는 장비값만 1600만원 정도(서부 경기문화창조허브), 전용 프로그램이 있음 실제 활용하고 싶을 경우 4층의 장비실 이용</p><p>퓨전, 맥스 등 다양한 3D 프린터</p><h2 id="_1-다운로드" tabindex="-1">1. 다운로드 <a class="header-anchor" href="#_1-다운로드" aria-label="Permalink to &quot;1. 다운로드&quot;">​</a></h2><p><a href="http://www.meshmixer.com/" target="_blank" rel="noreferrer">http://www.meshmixer.com/</a></p><ul><li>meshmixer 란 도서가 있음</li><li>32비트 이하는 되지 않음</li><li>버거워지면 팅기기도 함</li><li>남이 만든 것과 합쳐서 무언가를 만들 수도 있음</li><li>내부 밀도를 0으로 할경우 속을 비울 수 있음 그러나 찌꺼기가 남을 수 있음 (할로우 기능을 사용하는게 좋음)</li></ul><h2 id="_2-사용법" tabindex="-1">2. 사용법 <a class="header-anchor" href="#_2-사용법" aria-label="Permalink to &quot;2. 사용법&quot;">​</a></h2><p>import</p><ul><li><p>주름이 있어도 실제로는 주름은 나오지않음</p></li><li><p>xyz 프린터기</p></li><li><p>난반사일 경우 왜곡이 생김 ( 조명이 있어야 좋음)</p></li><li><p>Edit 일자로 자르는 것</p></li><li><p>Make Solid 퀄리티 재조정, 덩어리 형태로 모아온걸 합칠떄 하나의 덩어리가 아니므로</p></li><li><p>Make Pattern 임의의 상을 주는 것</p></li><li><p>Separate Shells 분리할떄</p></li><li><p>Add Tudb 관을 박음</p></li></ul><h2 id="_3-transform" tabindex="-1">3. Transform <a class="header-anchor" href="#_3-transform" aria-label="Permalink to &quot;3. Transform&quot;">​</a></h2><p>오른쪽 상단에 네모박스로 움직이거나 우측마우스누르고 , 휠 돌리기, 휠 누르고 좌우</p><ul><li>각도 조정은 빨간색 (각도잡고난 다음에 Accept 저장하면 그게 0이 되어버림)</li><li>Uniform Sacling 치수를 입력하면 다른 것도 자등으로 조정됨</li><li>완료 시 Accept</li></ul><p>오브젝트 기준 회전 View &gt; Recenter View</p><p>Plain Cut을 사용해서 맞추는 방법이 있음 (바닥에 붙여주는 것처럼 일직선을 만들어줌)</p><ul><li>우측 하단 verices 점의 개수 , 삼각형의 개수</li><li>W를 누르면 뭐가 생김</li><li>Reduce는 삼각형의수를 줄여서 퀄리티는 낮아짐 ( 작업시 무거울 경우 사용가능)</li><li>반대로 좋은거면 퀄리티를 높이는게 좋음</li></ul><h3 id="sculpt-조소를-하는-것-과-같음" tabindex="-1">Sculpt (조소를 하는 것 과 같음) <a class="header-anchor" href="#sculpt-조소를-하는-것-과-같음" aria-label="Permalink to &quot;Sculpt (조소를 하는 것 과 같음)&quot;">​</a></h3><ul><li>Lazyness적용되는 시간</li><li>Symmery반을 가르는 것</li><li>Flow 내가 누르고 있으면 계속 기능이 적용됨</li><li>브러시에서 드러우는 채우는 기능</li></ul><p>무작정 채우면 오류가 바랭할 수 있으므로 선택 (선택 후 휠로 크키 조정후 delete누르면 삭제됨 더블클릭 후 Eraser &amp; Fill틸로 채울수 있음</p><p>스캐너의 경우 할 떄 머리는 헝클어진 머리는 적용이 안되므로,</p><p>눈은 임의로 모델링해서 박아야함</p><ul><li>*핀치 안으로 깎는 기능</li><li>depth - 로 눈꺼풀 만드는 것 까지 가능</li><li>Falloff는 브러쉬 끝의 모양</li></ul><p>자연스럽게만드는 스무스하게 하는 기능이 있음</p><p>실제처럼 괜찮게 만드려면 후가공 잘하고 도색을 잘하면 잘됨</p><ul><li>머리카락 핀치 -50 하고 머리선을 만들고</li><li>드로우로 머리를 늎여 넣어줌</li><li>로버스트 스무스로 전체적으로 자연스럽게 만들어줌</li><li>브러쉬중 콘트롤을 누르면 반대로 작용함 드러우중 컨트롤 누르면 들어감</li></ul><p>c z cy</p><h2 id="_11시30분" tabindex="-1">11시30분 <a class="header-anchor" href="#_11시30분" aria-label="Permalink to &quot;11시30분&quot;">​</a></h2><ol><li>핸디용 스캐너(광학식 비접촉식) , 고급 스캐너의 경우는 레이저로해서 건물이나 산도 측량이 가능함</li></ol><ul><li>40센티정도의 간격을 유지해야 함</li><li>삼각대 구입하기</li><li>시리얼넘버입력 후 활성화코드입력한 것은 곧장 됨</li><li>사람(흉상)과 객체가 있음</li></ul><h3 id="스캐너" tabindex="-1">스캐너 <a class="header-anchor" href="#스캐너" aria-label="Permalink to &quot;스캐너&quot;">​</a></h3><ul><li>접촉식과 비접촉식스캐너의 경우 접촉식은 상업용</li><li>레이저 식과 광학식</li><li>머리카락은 스캔이 잘 안됨 짧거나 가느다란 경우 빛은 투과함</li><li>안경도 스캔이 잘 안됨</li><li>스캔시 움직이면 안됨</li><li>명암조절과 색조조절이 잘안됨, 너무 밝아도 안됨(조명도 중요 )</li></ul><h3 id="설정" tabindex="-1">설정 <a class="header-anchor" href="#설정" aria-label="Permalink to &quot;설정&quot;">​</a></h3><ul><li>해상도 최상</li><li>객체크기는 중형</li><li>객체인식은 주변의 물체도 인식하는것 (꺼놓는게 좋음)</li><li>표적링은 물체쪽을 가리키도록 하면 좋음</li></ul><p>키보드에서스페이스를 누르면 동작후 esc시 정지</p><ul><li>최대한 정면에서 시작하면 좋음</li><li>하얀부분이 없어질 떄까지 해주는게 좋음 (턱밑 , 귓볼 등이 잘안나옴</li><li>표적링을 가운데 두도 반대로 돌아도 됨</li><li>컬러를 안봐도 됨 스캔후에는 채우기 기능을 함</li><li>원하는 부분만 선택을 할 수 있음</li></ul><p>뿔처럼 나오는 부분이 있으면 지우기기능을 하면 레이저 맞은것 처럼 사라짐</p><p>마무리 후 도형화</p><ul><li>다음누르면 명조 대조도 등</li><li>다듬기는 자르기와 비슷 함 (바닥이 편평해지므로 자르기를 해주면 좋음 )</li><li>전용 홈페이지에 클라우드로도 가능</li></ul><h2 id="_14시" tabindex="-1">14시 <a class="header-anchor" href="#_14시" aria-label="Permalink to &quot;14시&quot;">​</a></h2><p>사진을 여러개 찍어서 랜더링을 3D 스튜디오를 하는 방식이 주를 이룸</p><ul><li>메이크 솔리드로 보정 복원</li><li>노즐 2미리면 두꺼움 0.8</li><li>액상프린터일 떄 할로우 기능을 씀 (Hoe Per Hollow로 구멍을 여러개 뚫어서 하기도 함)</li></ul><h3 id="메이크패턴" tabindex="-1">메이크패턴 <a class="header-anchor" href="#메이크패턴" aria-label="Permalink to &quot;메이크패턴&quot;">​</a></h3><p>앞에 원하는 패턴이 나옴</p><h3 id="측정하는-것" tabindex="-1">측정하는 것 <a class="header-anchor" href="#측정하는-것" aria-label="Permalink to &quot;측정하는 것&quot;">​</a></h3><ul><li>Measure</li><li>Overhangs 내가 하고싶은 만큼 각도를 조정함</li></ul><p>thinkercad를 잉크스케이프 이미지 &gt; svg &gt; 팅커케드로 불러들이면 다른 형상에 접목할 수 있음 파워포인트에서 이미지로</p><ul><li>Shade는 질감표현</li><li>STL Binary Format 을 사용</li></ul><h2 id="_15시-30분" tabindex="-1">15시 30분 <a class="header-anchor" href="#_15시-30분" aria-label="Permalink to &quot;15시 30분&quot;">​</a></h2><ul><li>리센트 뷰</li><li>오브젝트 뷰</li><li>싱기버스</li><li>모디파이에 스무스 바운더리를 하면 파란색 라인이 생김</li></ul>',48)]))}]]);export{r as __pageData,t as default};
